INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_234498','Ей, заграйте, гудаци','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Самвидавний туристський пісенник "Там на Лемковині помедже горами". - Літо, 1981.','Діалектизми: гудаци - музиканти, музики (на скрипці); калап - капелюх; мойой - моєї; ня - мене; павур - павич; стівка - сотня, сотка; тать - бо, адже.','Dm
