INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2345675','Свято Миколая','Музика: Віталій Лазаренко Слова: Раїса Обшарська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Дожидаються дорослі,
Діточки чекають
Того дня, коли настане
Свято Миколая.
Як прийде святий угодник
До нашої хати,
То у дзвоники задзвонять
Божі янголята.

Завітає і в багату,
І в бідну родину,
Не обмине, не покине
Найменшу хатину:
І цукерки та іграшки,
І бубликів в''язку
Подарує чемним дітям,
Ще й добро та ласку.

Тихесенько під подушку
Дари поскладає,
І чарівна добра казка
В танці закружляє.
І над цілою землею
Зорі засіяють,
Бо святого Миколая
Увесь рік чекають...','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2345675'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2345675','Свято Миколая','Дожидаються дорослі,
Діточки чекають
Того дня, коли настане
Свято Миколая.
Як прийде святий угодник
До нашої хати,
То у дзвоники задзвонять
Божі янголята.

Завітає і в багату,
І в бідну родину,
Не обмине, не покине
Найменшу хатину:
І цукерки та іграшки,
І бубликів в''язку
Подарує чемним дітям,
Ще й добро та ласку.

Тихесенько під подушку
Дари поскладає,
І чарівна добра казка
В танці закружляє.
І над цілою землею
Зорі засіяють,
Бо святого Миколая
Увесь рік чекають...');
