INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2346573','Танцювала карапет','Українська народна пісня. Виконує: Інна Книжник','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Танцювала карапет,
Порвала ботінки,
Осталися на ногах
Чулки да резінки,
А музики грають,        |
Аж чулки спадають,      |
А підошви з ботінок     |
Собаки таскають!        | (2)

Якби мені зранку
Горілочки чарку,
Не діда старого,
Хлопця молодого!
Я би з ним гуляла,      |
Всю нічку не спала,     |
Бо я жінка не свята,    |
В мене правдонька своя! | (2)

А дєвочка Рая
Упала з сарая,
Який тебе чорт послав,
Моя дорогая?..
Упала з сарая,          |
Порвала спідницю,       |
Ще й до смерті налякала |
Молоду телицю!          | (2)

Ресторан відкрили,
"Старт" його назвали,
Поруч витверезник,
"Фінішом" назвали.
Ой, не пийте, хлопці,   |
Міцної горілки,         |
Бо буде вам карапет     |
Від рідної жінки!       | (2)

Танцювала карапет,
Порвала ботінки,
Осталися на ногах
Чулки да резінки,
Ви, музики, грайте,     |
А ви, люди, чуйте,      |
В кого ноги не болять - |
Карапет танцюйте!       | (2)','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2346573'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2346573','Танцювала карапет','Танцювала карапет,
Порвала ботінки,
