INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2348212','Синє небо у вогні','Музика: позивний "Алькор" Слова: позивний "Алькор"','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Поверталися до дому
Птахи рано по весні,
Крила їх не знали втоми
Та зустріла їх земля в вогні...
Там, де мати їх ростила,
Де злетіли в височінь,
Де вони набрались сили -
Там тепер панує чорна тінь...

Приспів:
Синє небо у вогні,
Путін служе сатані.
З нами поруч Матір Божа -
Згине навіть тінь ворожа!
З нами ангели співають,
Бо герої не вмирають!
Божі ангели за нами -
Ми не будемо рабами!
Путін служе сатані!
Ми з тобою навійні!
Правда завжди переможе!
З нами поруч Матір Божа!
Слава наша не поляже,
А про себе ще розкаже!
З нами ангели співають,
Бо герої не вмирають!
Бо герої не вмирають!

Ні! Не житиме в неволі,
Хто з дитинства мав літать,
В нас нема другої долі,
Як свою свободу відстоять!
І коли під небом синім
Розіллється злато нив,
З Богом разом посміхнуться
Всі, хто рідну землю боронив!

Приспів. (2)','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2348212'), datetime('now')),datetime('now'));
