INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_234512','Де Коза xодить там Жито родить','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Де Коза ходить, там Жито родить! © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Українська Святочна установа Колядників походить з далеко старших часів, чим Римські та інші маскаради, які всі суть орієнтовані на культ Сонця і належать до пізнішого, вторинного, культурно-історичного округа. Українські ходження з Козою є зовсім іншого типу — і в них "Берези" нема. Вони належать передовсім до обрядів Новорічних і Щедровечірніх та лиш через перемішання з Різдвяними увійшли в Різдвяний час і мають свою власну мітольоґійну орієнтацію й характеристику. Де Коза ходить там Жито родить! Читати листки з приводу цієї Пісні: Щедрий Вечер, 13-14 січня: Миланки-Васильки. Щедрий Вечер, 18-19 січня: Святі Водорщі. Стежки до інших листків про Українські традиції.','Де Коза xодить там Жито родить!
Василько Козу по Селу водить
Де Коза Рогом там Жито Стогом
Де Коза стопою там Жито Копою
Ой чудо-чудо-чудо послуxайте Добрі Люде
Що далі буде!
Для Козуні в бубни-бубни
Для Сірої в Скрипки грають
