INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_234277','Свята ніч','Музика: Franz X. Gruber Слова: Fr. Joseph Mohr. Виконує: Руслана, Тарас Чубай','uk','ukraine_before_1917',NULL,NULL,NULL,'Підбір акордів: Роман Бучко','Свята ніч, тиха ніч,
