INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2348055','Завітає Рік Новий','Музика: Анатолій Салогуб Слова: Анатолій Салогуб','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Одягли свій наряд
Сосни та ялинки,
Вже сніжинки блищать.
Сяють мов перлинки.

Приспів:
В рідний край,
В рідний край
Йде зима весела!
Новий рік,
Новий рік
Йде в міста і села!

Ой, багато зима
Натрусила снігу,
Прийдуть знову свята
Дітям на утіху.

Приспів.

Ми про зиму пісні
Будемо співати,
Новорічний танок,
Як не станцювати.

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2348055'), datetime('now')),datetime('now'));
