INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2348165','Алілуя','Музика: Leonard Cohen Слова: Борис Базима','uk','ukraine_1991',NULL,NULL,'https://youtu.be/dyYqmCGTiLk','Пісню виконує Ігор Базима.','Під ясним небом голубим
На щедрім полі золотим
Слова хвали Творцеві возношу я!
Безцінний дар життя нам дав,
Любить цей світ заповідав.
Тобі співаю славу: Алілуя!

Алілуя! Алілуя! Алілуя! Алілуя!

Ти покараєш злих царів
За сльози наших матерів.
І Твою волю, як свою, прийму я.
Країна наша розцвіте,
Я знаю, Ти бажаєш це!
Тобі співаю славу: Алілуя!

Алілуя! Алілуя! Алілуя! Алілуя!

Ти - путь, Ти - правда, Ти - любов!
Мир надихаєш знов і знов.
Лише про одне Тебе молю я:
Не залишай ніколи нас,
Послухай, як серця весь час
Тобі співають славу: Алілуя!

Алілуя! Алілуя! Алілуя! Алілуя!','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2348165'), datetime('now')),datetime('now'));
