INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_235022','Там за Дунаєм Музиченьки грають','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаївки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... Буде Тобі Три Дорозі. У Скрипочку грає хороше співає. Символіка Щедрого Вечера і Василя. Щедрий Вечер зачинається властиво під Новий Рік, 13-14 січня (7 днів наперед Богоявління — символ Місячний!), т. є. в вечер перед св. Василя. Це особливо улюблене Українське свято: мітичного Василя і Маланки, — є найщирішим шануванням Місяця з його женихальними мотивами (ними переповнені Щедрівки). Тоді мітичну постать Василя мішають часто з мітольоґійно-Місячною постаттю Іллї — Ілії, який є в Українського народу покровителем урожаїв збіжжя, особливо жита (сніп жита, дід Ілля, — в часі жнив, — це постава Місяця). Читати листки з приводу цієї Пісні: Щедрий Вечер, 13-14 січня. Маланки-Василь. Коза. Щедрий Вечер, 18-19 січня: Святі Водорщі. Стежки до інших листків про Українські традиції.','Там за Дунаєм Музиченьки грають

Приспів:
В Зеленім Гаю там при Дунаю.

Там Івасенько Кониченька пасе
Коника пасе на Скрипці грає
На Скрипці грає ще й Танці водить
Ще й Танці водить все вперід ходить

Прийшла до нього Матінка Його
Час Мій Синоньку час додомоньку
Я зараз піду но Танцю дійду
Тай Танцю дійшов додому не прийшов

Прийшов до нього Батенько Його
Час Мій Синоньку час додомоньку
Я зараз піду но Танцю дійду
Тай Танцю дійшов додому не прийшов

Прийшла до нього Миленька Його
Час Мій Миленький час додомоньку
Я зараз піду но Танцю дійду
Як Танцю дійшов додому прийшов

Бувай нам здоров наш Івасеньку
Не сам з собою а з челядою
В Зеленім Гаю там при Дунаю','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_235022'), datetime('now')),datetime('now'));
