INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2351073','Зима','Музика: Олена Титорчук Слова: Юлія Хандожинська','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Зимонько, зимонько, зимонько-зима,
В тебе тепла шубка біла хутряна,
І мороз колючий вже не налякає,
Мабуть, він про тебе добре усе знає.

Приспів:
Ой, зима, ой, зима
Гори снігу намела,
Хоч мороз тріщить, лютує,
Та зима його не чує,
Не боїться, не тікає,
Бо пухнату шубу має.

Замела стежини, замела горбочки,
Зашила ставочки в крижані сорочки,
Зеленим ялинкам дала по хустинці,
Ось такі лісові зимові гостинці.

Приспів.','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2351073'), datetime('now')),datetime('now'));
