INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2352216','Новий Рік!','Музика: Сергій Ярунський Слова: Ольга Яриновська','uk','ukraine_1991',NULL,'2017','аудіозапис','Пісню виконує вокальний ансамбль "Намистечко". Прем''єра пісні відбулась 1 січня 2017 року у програмі "Доброго року, Україно" (І частина, центральний канал).','Зима малює на вікні
Узори, виткані морозом,
Забула річенька пісні,
Тихенько спить
Під верболозом...
Сидять на вітах снігурі,
Накрив у крижаних сережках,
Укриті килимом всі стежки,
Святковий день в календарі.
Красуня біла заметіль
Чекає коляду за рогом,
А Дідух - сивий оберіг -
Стрічає гостей за порогом.
Чаклун зі скринею дарів,
Тепла, турботи і любові,
В різдвяній золотій онові
Спішить, летить на крилах мрій!

Приспів:
Новий Рік! Новий Рік!       |
Новий Рік                   |
Заблукав в павутинні доріг! |
Королева зима               |
Свято казки у дім принесла! | (2)

Завершив Старий Рік політ,
Тік-так - годинник поспішає,
І рветься стрімко стрілка вбік,
Нова історія чекає!
Чаклун веселий Рік новий
В оселю кожну завітає,
Здійснить, що серце забажає,
Наповнить щастям келих твій!

Приспів.    Фонограма-мінус (mp3, 320 kbps)','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2352216'), datetime('now')),datetime('now'));
