INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2351990','Купальський віночок','Музика: Сергій Ярунський Слова: Богдан Коханевич','uk','ukraine_before_1917',NULL,NULL,'https://www.youtube.com/watch?v=06eW8curQ2U','Пісню виконує аматорський хор районного будинку культури села Ярунь.','На Йвана Купала я вінок сплітала,
Стежечка до річки стелилася нам.
Тихо усміхнувшись до тебе сказала:
Хто зловить віночок - серце я віддам!

Купальський віночок поплив за водою.
Кружляє, пірнає, несеться бистрінь.
Поплив по річці, шукаючи долю,
Заглядають квіти у чорну глибінь...

Любисток і ружі, барвінок зелений
І волошки сині я туди вплела.
Відпливав віночок все швидше від мене,
Далеко-далеко вода понесла...

В очі ти поглянув - кинувся у воду,
По глибокій річці за щастям пливеш.
Буде кохання тобі в нагороду,
Якщо мій віночок ти в ночі знайдеш!..','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2351990'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2351990','Купальський віночок','На Йвана Купала я вінок сплітала,
Стежечка до річки стелилася нам.
Тихо усміхнувшись до тебе сказала:
Хто зловить віночок - серце я віддам!

Купальський віночок поплив за водою.
