INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2352879','Материнське горе','Музика: Володимир Сірант Слова: Володимир Сірант. Виконує: Володимир Сірант','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Матері, ви від горя
Умиті сльозами,
Матері, ну за що вас
Торкнулась біда?
День за днем плачете
За своїми синами,
Плаче також за ними
Черешня в саду молода...

Приспів:
Матері, не для того
Синів ви ростили,
Щоб вони від руки
Свого брата лягли.
Любі наші, дай Боже
Терпіння вам,
Здоров''я і сили,
Дочекатись часу -
Їх побачить живими змогли!
Боже, ти сили дай мамі,
Боже, здоров''я дай мамі -
Під кулями син прочитає
Молитву свою.
Боже, ти сили для сина,
Боже здоров''я для сина,
Просить мати його
Захистити в нерівнім бою!

Матері, сльози витріть
І будьте ви горді тим,
Що ваші сини захищають
Країну в бою!
І хоч як не крути
Та прийде перемога поволі,
Повернуться сини,
Кожен маму зустріне свою!

Приспів.','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2352879'), datetime('now')),datetime('now'));
