INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2352550','Новорічна ніч','Українська народна пісня. Виконує: Алла Мігай','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Тік, так, тік так,
Рухається стрілка,
Все не так, все не так,
Все життя - помилка,
Снігопад, зорепад,
Новий рік на носі,
Подарунки до свят
Дід Мороз розносить...

Приспів:
Новорічна ніч -
Добре свято,
Новорічна ніч -
Мрій так багато,
Новорічна ніч
Витре сльози!
Проведи її разом
З Дідом Морозом.
Новорічна ніч -
Не заплющуй віч!
Вірю станеться диво -
Знову буду щаслива
В Новорічну ніч!

Тік так, тік, так,
Час іде невпинно,
Новорічні свята,
А на серці зимно,
Завиває віхола
І у двері грюка,
І годинник тікає,
Наче серце друга.

Приспів.

Новорічна ніч -        |
Не заплющуй віч!       |
Вірю, станеться диво - |
Знову буду щаслива     |
В Новорічну ніч!       | (2)

Тік, так, тік, так,
Тік, так...','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2352550'), datetime('now')),datetime('now'));
