INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_235457','Моя мила, премила, премила','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1965','1. З пам''яті; 2. Пісні з Львівщини. - К.: Музична Україна, 1988. С. 130. 3. Лемківські народні пісні. Обробка для голосу в супроводі фортепіано. // Упорядник І. Майчик. - К.: Музична Україна, 1970. - С. 36.','Основний текст з незначними відмінами поданий за джерелом 2. Там же: Записана 1965 року в м. Дрогобичі від В. М. Рудого. **У джерелі 3 подана лише перша в''язка тексту з цими відмінами. Діалектизми: вірне, вірні - вірно; вічні - вічно; глядай - шукай; жовнір - солдат; премила - дуже мила, гарна, люба; фраїр - парубок, з яким ходить дівчина, коханий; хцеш - хочеш; ю - її.','Моя мила, премила, премила,
Шукай собі иншого фраїра,*
Бери собі, як знайдеш, як знайдеш,
Бо ти моя не будеш, не будеш.**

Моя мила, премила, премила,
Дальше ми ся дорога встелила,
Ой иду я на войну, на войну,
Сам не знаю, чи верну, чи верну.

Ждала, ждала премила, премила,
Вже ся война скінчила, скінчила,
А дівчина вірне жде, вірне жде,***
Може милий поверне, поверне.

Ой у полі могила, могила,
Її цвітом черемшина вкрила,****
Вітер листям шелестит, шелестит:
Жовнір вічні отут спит, отут спит.
*Варіант рядка:
Глядай собі иншого фраїра;

**Варіант в''язки:
Моя мила, премила, премила,
Бери собі фраїра, фраїра;
Бери собі кого хцеш, кого хцеш,
Бо ты моя не будеш, не будеш.

***Варіант рядка:
А дівчина вірні жде, вірні жде;

****Варіант рядка:
Черемшина цвітом ю покрила','[''pisni.org.ua'', ''cat:lemkivski'', ''cat:rekrutski'', ''Лемківські пісні'', ''Рекрутські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_235457'), datetime('now')),datetime('now'));
