INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_235471','Щоб співати колір чорний, взяла б голос твій','Музика: невідомий Слова: Степан Руданський. Виконує: Василь Триліс, Ольга Богомолець','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Щоб співати колір чорний,
Взяла б голос твій,
І тобі одна покорна
Я співаю колір чорний,
Бо то колір мій.   | (2)

В чорну днину мене мати
На світ привела.
Чорні очі мені дала,
Чорні думи вколихала,
Ой, чорні, як ніч,
Як осіння ніч.

Ох, ніхто вже не згадає
Нишком про мене,
І хлопчина не пригорне,
Не згадає очі чорні
І не спом''яне.     | (2)

Щоб співати колір чорний,
Взяла б голос твій,
І тобі одна покорна
Я співаю колір чорний,
Бо то колір мій.   | (2)','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_235471'), datetime('now')),datetime('now'));
