INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_235624','Б''ють літаври гучні','Музика: Ярослав Ярославенко Слова: Василь Пачовський','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'1. Пісні Українських Січових Стрільців. - 1990 (Самвидав)','Підбір акордів: bohdanko (pisni.org.ua)','Б''ють літаври гучні, ясні сурми гремлять,
Іде Січ, грають полки, як море,
Бунчуки піднялись, хоругви шамотять
Через гори і доли, і бори!

Приспів:
Січ іде! Січ іде! Січ іде, стяг несе, |
Україна встає, Україна гуде,          |(2)
Україна клекоче, як море!             |

Довбуш трубить з верхів: зруйнував цар нам Січ,
Ми втекли в сині гори з трубою...
Двіста літ спали ми, - стрепенулася ніч,
Ми зірвались і трубим: до бою!

Приспів.

В нашій Січи давні Запорожці встають,
Голос труб кличе: в лави ставати!
Ми стаєм, в бій ідем, перші стріли гудуть,
Заревуть в Україні гармати!

Приспів.

На нас дивляться всі: наш Хмельницький Богдан,
Дорошенко, Мазепа, Виговський,
Всі гетьмани за нас, всі кріваві від ран,
Гей, Ляхи, і ти, царю московський!

Приспів.

Акорди у тональності G (за джерелом 1):
Б''ють літаври гучні, ясні сурми гремлять,
Іде Січ, грають полки, як море,
Бунчуки піднялись, хоругви шамотять
Через гори і доли, і бори!

Приспів:
Січ іде! Січ іде! Січ іде, стяг несе,
Україна встає, Україна гуде,
Україна клекоче, як море!
Січ іде! Січ іде! Січ іде, стяг несе,
Україна встає, Україна гуде,
Україна клекоче, як море!','[''pisni.org.ua'', ''cat:himny-marshi'', ''cat:istorychni'', ''cat:rekrutski'', ''cat:strilecki'', ''cat:suspilno-politychni'', ''Гимни та марші'', ''Історичні пісні'', ''Рекрутські пісні'', ''Стрілецькі пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_235624'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_235624','Б''ють літаври гучні','Б''ють літаври гучні, ясні сурми гремлять,
Іде Січ, грають полки, як море,
