INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2354','Господи, помилуй нас','Музика: Тарас Петриненко. Виконує: Тарас Петриненко','uk','ukraine_1991',NULL,NULL,'пісенник Шестака',NULL,'Навіть на останнім рубежі
Промінь віри в нас ще не погас,
Боже, Україну збережи,
Господи, помилуй нас.
Нам свою всемилість покажи
Правдою повсюди й повсякчас,
Боже, Україну збережи,
Господи, помилуй нас.

Помилуй Господи
Am-F
Помилуй Господи
Господи помилуй нас.

В наших грудях кулі і ножі,
Нас розіп’ято й знищено не раз,
Боже, Україну збережи,
Господи, помилуй нас.
І з колін піднятись поможи
І благослови у добрий час
Боже, Україну збережи,
Господи, помилуй нас.

Наші душі нидіють в іржі,
Але промінь віри не погас,
Боже, Україну збережи,
Господи, помилуй нас.
Грішні діти - діти не чужі,
Отче наш, почуй їх щирий глас,
Боже, Україну збережи,
Господи, помилуй нас.','[''pisni.org.ua'', ''cat:christian'', ''cat:patriotic'', ''Пісні на християнську тематику'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2354'), datetime('now')),datetime('now'));
