INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2354461','Гімн Придністровської Молдавської Республіки','Музика: Борис Александров Слова: Борис Парменов, Ніколас Божк, Віталій Пищенко','uk','ukraine_1991',NULL,NULL,'https://uk.wikipedia.org/wiki/%D0%93%D1%96%D0%BC%D0%BD_%D0%9F%D1% 80%D0%B8%D0%B4%D0%BD%D1%96%D1%81%D1',NULL,'Ми славимо край Придністров''я,
Де люди пишаються тим,
Що дружбою, ладом, любов''ю
Навіки пов''язані з ним!
Прославимо наші заводи,
Широкі лани і міста,
Тут чесно працюють народи
На благо Вітчизни труда!

Приспів:
Через доли і води
Пронесемо ім''я
Ми Республіки свободи,
Хай живе тут народів сім''я!

Ми славимо рідні долини,
Красоти Дністра берегів,
І нам не забути билини
Про подвиги наших батьків!
Прославимо всіх поіменно,
Полеглих за наш отчий дім,
Де пам''ять загиблих священна,
Вітчизні співаємо гімн!

Приспів.','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2354461'), datetime('now')),datetime('now'));
