INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_235616','Гей, браття, опришки','Музика: Анатолій Кос-Анатольський Слова: Микола Устиянович. Виконує: Орфей, Акорд','uk','ukraine_1991',NULL,NULL,NULL,'Текст записано на слух з аудіо. * Тут у тексті я не впевнений; потребує уточнення.','Гой-я, гой-я, гей!

Гей, браття, опришки, налийте горілки,
До ватри докиньте ще дров.
Настрійте ми горло голосом сопілки,
А я вам співати готов.

Приспів:
Гой-я, гой-я, гей! (2)
Гой-я, гой-я, гой-я, гой-я!
Дана, дана, дана, дана!
Гей, браття опришки, затанцюємо аркана!
Гой, гой, гой-я, дана, гой-я, дана!
Прийди, прийди, подивися, дівчино кохана!
Гой-я, гой-я, гой-я, гой-я, гей!

Гей, браття, опришки, годі сумувати,
Ще жевріє зелень в ярі. *
Краще раз літати соколом в Карпати,
Ніж весь вік стогнати в ярмі.

Приспів.

Гой-я, гой-я!
Гой-я, гой-я, гей!','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_235616'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_235616','Гей, браття, опришки','Гой-я, гой-я, гей!

Гей, браття, опришки, налийте горілки,
До ватри докиньте ще дров.
Настрійте ми горло голосом сопілки,
А я вам співати готов.

Приспів:
Гой-я, гой-я, гей! (2)
Гой-я, гой-я, гой-я, гой-я!
Дана, дана, дана, дана!
Гей, браття опришки, затанцюємо аркана!
Гой, гой, гой-я, дана, гой-я, дана!
Прийди, прийди, подивися, дівчино кохана!
Гой-я, гой-я, гой-я, гой-я, гей!

Гей, браття, опришки, годі сумувати,
Ще жевріє зелень в ярі. *
Краще раз літати соколом в Карпати,
Ніж весь вік стогнати в ярмі.

Приспів.

Гой-я, гой-я!
Гой-я, гой-я, гей!');
