INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2360697','Не буду ся женити!','Музика: Іван Мадяр Слова: народні. Виконує: Іван Мадяр','uk','ukraine_before_1917',NULL,NULL,'https://youtu.be/mQSymGobXDc','Пісню виконує Іван Мадяр.','Пішов Іван в полонину косити,
Пішло за ним дев''ять дівок сушити.
Та й накосив дев''ять валів в один день -
Не посушать дев''ять дівок за тиждень!

Приспів:
Не буду ся женити,
Лем так буду ходити
Межи тима горами
За чужими жонами!
Чужі жони такі суть -
Палиночки принесуть,
Палиночки ще й вина:
Пийте, хлопці, до рання!

Любилась ня цілий тиждень, гея-гой!
Забулась ня на восьмий день, гея-гой!
Не велика серцю туга, гея-гой!
Не будеш ти, буде друга, гея-гой!

Приспів','[''pisni.org.ua'', ''cat:zakarpatski'', ''Закарпатські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2360697'), datetime('now')),datetime('now'));
