INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236165','Нема льоду, нема льоду','Українська народна пісня','uk','ukraine_before_1917',NULL,'1910','1. Пісні однієї родини. - К.: Музична україна, 1988. - C. 23','Пісня з репертуару родинного ансамблю Палунів Марії Іллівни (1910 р. нар.) та Андрія Пилиповича (1908-1982) - мешканців села Волошнівки Роменського району на Сумщині.','Нема льоду, нема льоду, нема переходу,
А хто кого вірно любить, прийде через воду.

Покочу я для потішки чотири орішки,
Як немає пари коней, прийди, серце, пішки.

Як немає пари коней, ще й пари жупанів,
Прийди, серце, до чорних брів, до шитих рукавів.

Що ті шиті рукавечка і в долу мережка,
Аж до тої дівчиноньки протоптана стежка.

Топтав, топтав доріженьку - та взяв запечатав,
Щоб моєї дівчиноньки ніхто не посватав.

Де взялися попи, дяки - та й розпечатали,
Де взялися вражі люди, - дівку посватали.    Голос 1','[''pisni.org.ua'', ''cat:slobozhanski'', ''cat:vesnyanky-hayivky'', ''Пісні з слобожанщини'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236165'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_236165','Нема льоду, нема льоду','Нема льоду, нема льоду, нема переходу,
А хто кого вірно любить, прийде через воду.

