INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236073','Ой піду я в полонину','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Пісні з Полонини(закарпатські народні пісні)-К.:видавництво"Дніпро",1973р.',NULL,'Ой піду я в полонину,
Ой піду я лугом,
