INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236091','Коли розлучаються двоє','Музика: Микола Лисенко Слова: Генріх Гейне. Виконує: Піккардійська Терція, Іван Козловський, Вікторія Лук''янець, Петро Бойко, Тарас Ященко, Борис Гмиря, Олександр Таранець','uk','ukr_ssr_1919_1991',NULL,'1935','1. Українські народні романси. - К.: В-во АН УРСР, 1961. - С. 194. 2. http://leonpar.narod.ru/Kopilka.HTML','Ця пісня - одна з улюблених Івана Семеновича Козловського. Її він тричі записував у дуеті з М.Гришком (1935 р.), Ан. Івановим (1950 р.) та Б.Гмирею (1957 р.). Прослухати один з найкращих записів пісні у виконанні Соломона Хромченка (етнічного єврея, що народився в Україні у містечку Золотопіль, з юних літ співав у синагозі, згодом став солістом Большого театру) та Костянтина Лаптєва (етнічного росіянина, уродженця Києва, що співав в Одеській, Київській та Ленінградській операх) можна тут. У джерелі 1 є посилання на першоджерело: Українські народні пісні, кн. 2. - К.: Мистецтво, 1954. - С. 386.','Коли розлучаються двоє,
За руки беруться вони,
І плачуть, і тяжко зітхають,
Без ліку зітхають сумні.

З тобою ми вдвох не зітхали, |
Ніколи не плакали ми,        |
Той жаль, оті тяжкі зітхання |(2)
Прийшли до нас згодом самі!  |','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236091'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_236091','Коли розлучаються двоє','Коли розлучаються двоє,
