INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236379','Весно ж наша красна','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Народні співи Галичини. Гаївки. Зібрав та упорядкував М. Мишанич. Львів, «Гердан», 1991','Запис із с. Щуровичі Радехівського району Львівської області','Весно ж наша красна,     | (2)
