INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2363354','Купальська',NULL,'uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує Ольга Петлюх.','Зілля духмяне, лагідні очі.
Цвіт дивовижний посеред ночі,
Казка прадавня, скупана в росах,
Ходить марена травами боса...

Приспів:
Ой, на Івана, да й на Купала
Зірка у воду перша упала...
Ой, на Івана, на Купала,
Дух полиновий небо над нами,
Доля дівоча в річці не втоне!..
Ой, на Івана, на Купала...

Вогнищем небо, мить неповторна,
Народної пісні сила поборна...
Між цим всім сниться все заповітне -
