INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2365192','Ой, чого ж ти, мамо?','Музика: Микола Янченко Слова: Микола Янченко. Виконує: Микола Янченко, Таня Денисюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ой, чого ж ти, мамо, посивіла рано?
А була ж у тебе золота коса.
Це тому, мій сину, що життя з полином  |
Бог у мою косу зачесав...              | (2)

Ой, чому ж ти, мамо, пісню не співаєш,
Чом скрипаль для тебе вже мовчить?..
Це тому, мій сину, що нема родини,     |
Лиш сова самотньо закричить...         | (2)

Знов в віконце мами кутають тумани
І не видно стежки до воріт...
Вже не йдуть до хати маму привітати    |
Діти і онуки стільки літ...            | (2)

Доля нещаслива, голівоньку сиву
До кого на старість прихилить?..
Відцвіла, як вишня, стала дітям лишня, |
Ой, як моє серденько болить!..         | (2)

Ой, чого ж ти, мамо, посивіла рано?
А була ж у тебе золота коса.
Це тому, мій сину, що життя з полином  |
Бог у мою косу зачесав...              | (2)','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2365192'), datetime('now')),datetime('now'));
