INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236461','Ой у Вишневому Саду там Соловейко щебетав','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002 2. Українські народні пісні з голосу Антоніни Голентюк. Пісенник. - К.: Музична Україна, 1991','Весна Світа. Еротика: Катерини – Калета – Андрія... Гаївки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... Весна іде Красу несе і тій Красі радіє все. А вже Весна Красна А вже Весна скресла (2) Благослови Мати Весну закликати Весно Наша Весно що Ти нам принесла (3) Вже Весна воскресла Вже Весна воскресла (3) Ой у Вишневому Саду там Соловейко щебетав Яка чудова Майська Ніч. Ой у Вишневому Саду там Соловейко щебетав Пане Господарю вставай з Постелі А на тій Вербі Рожеві Квіти. Буде тобі Квітка Красна. Май. Цей весняний місяць, — то синонім незрівняної, роскішної, молодечої і в повнім розвитку краси природи: свіжого воздуху для грудей, молодої зелені в соковитих ростинах, розцвіту запашних цвітів, щебету птичок, ясного сонця. Одним словом: місяць Май це образ краси й роскоші. В цілім світі окликаний місяцем любови. А ось що означує по-іранськи слово Май: maya, femin., — втіха, роскіш, блаженність, саме щастя; те саме значить mayas, neutrum (Староіранське). Mayah, neutr.; mayavant, mayakan, adjectiv, — запліднення, полова сполука (Begattung). В Українського народу Іранська назва Май зовсім асимілювалася й принялася з усею його ідеольоґією. Цим словом називає нарід також місяць Серпень, стоячи перед роскішним, доспілим, зібраним збіжжям — своїм добром і втіхою своєї праці. Називає його Маїк; хоч впадає в очі різниця в степенях: це не дійсний Май, — а Маїк (маленький). Маєм називає нарід зрубане зелене гілля, для святочного "замаєння" хат. Майний — значить — з богатим листям (reichbelaubt). Майка, по-українськи, значить "еспанська муха" — cantharides (plural), відома з своєї властивости в медицині, як половий стимул; слово відповідне Іранському mayakan (гл. в.). Поминувши несказанну красу Весняної природи, яка в Маю вся в цвіту і безлічі красок, — в очі б''є по всіх усюдах народження нової твари, нового життя з його бажаннями, поривами й змаганнями. Цілі народи в Маю оживають та рвуться до життя, шукають його змісту і ціли. А Ти їй дай такий одвіт яка чудова Майська ніч Принесла вам Красу Господарську Рясу Стали Хусточки маяти cтала Діброва палати Листки з приводу цієї Пісні: Про Українські назви місяців Марець і Май. Гаїлка-Великдень — Українське Свято Відродження Світа. Стежки до листків про Українські традиції. Підбір акордів: Роман Довгаленко','Ой у Вишневому Саду там Соловейко щебетав
Додому я просилася а ти мене все не пускав      |(2)

Ой Милий Мій а я Твоя пусти мене зійшла Зоря *
Проснецця Матінка Моя буде питать де була я     |(2)

А Ти їй дай такий одвіт яка чудова Майська Ніч
Весна іде Красу несе і тій Красі радіє все      |(2)

Ой Доню-доню в чому річ де Ти блукала цілу ніч
Чому розплетена коса а на очах бринить сльоза   |(2)

Коса розплетена моя її Подруга розплела
А на очах бринить сльоза бо з Милим у розлуці я |(2)

Ой Мамо-Мамо й Ти була як я Дівчина-молода
Я жити хочу я люблю Мамо не лай Доньку свою     |(2)
*Відміна:
О Милий Мій молю Тебе зійшла Зоря пусти ж мене','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''cat:lirychni'', ''cat:narodni'', ''cat:vesnyanky-hayivky'', ''Пісні про красу природи'', ''Пісні про кохання, ліричні'', ''Народні пісні'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236461'), datetime('now')),datetime('now'));
