INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236515','А ми в Кривого Танцю йдем Танцю йдем','Українська народна пісня. Виконує: Етнографічний хор Гомін','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаївки-Великдень: Українське свято Відродження Світа. Гра-коловід Змії/Змія. Весна Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... А ми Йому Кінця не знайдем. Що виведу то ввірветься то Мій Милий засміється. А Хто хоче Кінець вести Треба Йому Вінець сплести. Не вивести Концю Коню Вороненький. А в Кривого Танця та не виведем Кінця А в Кривого Танця та не виведу Кінця А в Кривого Танця та не вивести Кінця А в Кривого Танцю та не виведу Кінця (2) А в Кривому Танцю не вивести Концю А ми Кривого Танцю йдем А ми Кривого Танцю йдем (2) (Кривий Танець) Ми Кривого Танцю йдемо Ой Кривого Танця та не виведем Кінця Стала ж Вона сяяти. Стали Хусточки маяти cтала Діброва палати. Скільки в Цебрі Водиці cтільки в Дівчат Правдиці. Ой Вінку Наш Вінку Хрещатий Барвінку. Гей нумо-нумо заплетімо Шума. Ой Данчику Білоданчику поплинь. Шиє-малює Злотом гаптує. Ой Ми зіслані на признаванє. Ми кривого танцю йдемо У Містечку Богуславі Каньовського-пана Вуж/Змія як Місячний символ. Переважаючу долю в Астральній Трійці перейняв Місяць. Це покажеться зовсім виразно з дальшого розгляду Астральної Трійці і взагалі Української Астральної реліґії, в якій розвинулось було широко шанування Місяця, передовсім у зв''язку зі Святом Щедрого Вечера. Але замітне є — як вже було згадано — в Українській Астральній реліґії окреме поєднання культових об''єктів, а саме: шанування Місяця і Зорі з виключенням Сонця. Я завважив також у символіці, стосованій до Святочного печива, якнайвиразніше зазначуване шанування Місяця і Зорі (у двійку) — див. також розділ: Бог і Астральна Двійця. Так приміром я бачив (в Конюхах, Бережани) Великодні Паски, на яких посередині була вироблена з тіста, артистичними півкругами, велика восьмикінчаста Зоря (ассирійська восьмираменна звізда!), а по чотирьох рогах доокола Зорі були зображення Місяця очевидно 4-х його фаз у подобі чотирьох вужиків. Щодо Паски з мітольоґійними емблемами, ставлю здогад, що вона може бути також поєднаним символом Астральної Трійці, в такий спосіб, що сама Паска — це Сонце, а над нею Зоря і Місяць у подобі Чотирьох Вужів. Вуж як символ Місяця був популярний у цілім стариннім Сході, особливо у Вірменії. Та Вуж (Змія) як символ Місяця проходить лиш у декількох Щедрівках — це може бути ідея неавтохтонна, і занесена на Україну. Її видно, окрім у згаданих прикрасах на Пасках, ще в Гаїлкових хороводах. А ми Йому Кінця не знайдем Але може бути, що Вуж як символ Місяця є лишень менше популярним в Українського народу в цій формі, себто у виразній своїй подобі, а особливо з огляду на Свято Різдва, в якім є многота вищих та ідеальніших по думці народу мотивів. І треба те завважити, що ідея Вужа як святости занадто суперечить біблійно-християнським поглядам на Вужа, символа сатани, — і тому може бути Українським народом ухилена з християнського погляду або скоріше захована від такого погляду. Змієве Озеро. Як приклад дійсного колишнього шанування Змія, чи Змії, між Українським народом, є також згаданий вислів Гуцула-Господаря, що вийшов перед Святою Вечерею на своє обійстя з жертвенним приносом та промовляв: "На Свят Вечер родив''ємся, на Свят Вечер хрестив''ємся! Пречиста Діва на Золотім Крижмі мя держала, у Змієвім Озері мя купала!" Змієве озеро — це мітичне, а заразом реальне озеро на Гуцульщині. Є це мабуть одно з так званих морських Ок-безодень. Після Гуцульських переказів живе в нім "планета", цебто нечистий дух, що поневолив грішні душі померлих та тримає їх у цім озері й каже їм з ледяних криг град та зиму (сніг) товчи, на пакість людям. Вода в цім Змієвім Озері зимна, як лід. Сама назва нечистої сили — "планета" — допускає здогад, що тут мається до діла з Астральною колишньою реліґією, тепер осудженою християнством. Згадка Гуцула про своє нарождення на Свят-Вечер — це натяк на Різдво Світа і зродження Чоловіка. Купіль новонародженого в Змієвім Озері — це наче рівнобіжність до Тайни Хрещення; а Святочний настрій Гуцула, з яким він про цю Купіль згадує, свідчить, що він вважає Змієве Озеро не лиш освіжаючою й скріпляючою водою, але й містичною животворною Силою — з часів, коли Змій був добрим ґенієм Народу. Золоте Крижмо, на яке покликується Гуцул, — це безперечно символ Астрального блиску. В Щедрівках все суть Місячними символами: Золотий Човник, в якім сидить або лежить "Білий Молодчик", Сріберні весла при Човні; Золотий стільчик, Золота Колиска, — взагалі як золото або срібло блискучі предмети, що скріплюють Місячну символіку головного мотиву, яким є звичайно Дитя, Молоде Пахоля або Білий Молодчик. Мабуть, отже й Золоте Крижмо, а на нім дитятко гуцульське є таким Місячним символом. Його прототипом Змій серед Озера — Місяць серед глибіні Небес — творчий чинник у Почині Світа. (Див. також: На День Добрий Панє-Господару до Тебе). Змія як Добрий ґеній народу. Щедрівок про Змію є всього кілька. У всіх виступає Змія як добрий ґеній молоді й посередник у женихальних справах; тому завсіди її щадять, не стріляють. (Див. також: Гаїлковий Білоданчик і Первісний Молодець-Стрілець). Зовсім анальоґічна до них є одна білоруська пісня про Змію, її мітичну долю та відношення до Стрільця-молодця. Натомість Великоруські пісні-перекази про Змія (прим. пісня про купіль Добрині), в яких Змій вважається за злу й погубну силу, — і гине з руки Молодця-лицаря. Поширення мотиву Змії між деякими Слав''янами та в світовій мітольоґії свідчить про його колишнє спільне походження. Але цей мотив на Україні ріжниться від світового. Є ориґінальний своїми мітольоґійними образцями й ідеєю Змія як Доброго ґенія народу. Боротьба на Україні між ідеєю Змії як доброго або злого духа — це не лише наслідок біблійних та християнських культурно-реліґійних впливів, але також, і передовсім, від первісного Українського культурно-реліґійного світогляду. Ми увидимо понижче, підчас критичного розгляду Колядок і Щедрівок, що пракультурний Український світогляд не знав ідеї злого духа. Про нього нема ніякої споминки в Староукраїнських Різдвяних обрядах, ані в Колядках, ні в Щедрівках. З поміж 1000 Колядок і Щедрівок є лише три, що згадують про диявола "мирського царя". Вони пройняті християнською реліґійною ідеольоґією, а в основі є походження чужого. Юр і народне шанування Змія та Місяця. Народна віра в Бога. З господарських свят первісних народів виходить, що їх мотивом є також бажання народу усвідомлення собі того Найвищого Єства в природі, що дає їм спроможність життя, даючи їм земні плоди й худобу. І в слід за тим стає мотивом Свята реліґія вдяки для Найвищого Єства.... Святочні обряди, пісні та пляси народів природи зроджують у них ідею Бога. Вони є тими середниками, що викликують у народу почуття близькости Бога, яка є неодолимим бажанням народу і його потребою... А ми в Кривого Танцю йдем Танцю йдем Володар Володар й одчиняй Ворота Іва на Купала тай в Воду упала (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Листки з приводу цієї Пісні: Про Українські назви місяців Марець і Май. Коляда і Великдень: Різдво і Відродження Світа Гаїлки-Великдень — Українське Свято Відродження Світа. (Вибір Пісень) Стежки до листків про Українські традиції.','А ми в Кривого Танцю йдем Танцю йдем
