INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2366394','Не ридай мене, Мати','Слова: Назар Незнаний','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує тріо священників "Новий Час".','Не ридай за мною, Мати...
Не ридай же, не ридай...
Не ридай за мною, Мати...

Опустилась правая рука,
Покотилася сльоза гірка,
Стала Сина із хреста знімати...

Не ридай за мною, Мати...
Не ридай же, не ридай...
Не ридай за мною, Чиста...

Із лівиці витягають цвях,
Руки Сина в Матері руках,
Руки зморені до свого серця тисне...

Не ридай за мною, Чиста...
Не ридай же, не ридай...
Не ридай за мною, Діво...

На землі заколене ягня,
Матір невидюща навмання
Обмиває свого Сина тіло...

Не ридай за мною, Діво...
Не ридай же, не ридай...
Не ридай за мною, Панно...

То не мира-нарду рідина -
То Марії сльози, то вона
Плакала, співаючи: Осанна...

Не ридай за мною, Панно...','[''pisni.org.ua'', ''cat:strasni'', ''Страсні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2366394'), datetime('now')),datetime('now'));
