INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236675','А в Кривого Танцю та не виведу Кінця (2)','Українська народна пісня. Виконує: Христина Охітва','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаївки-Великдень: Українське свято Відродження Світа. Гра-коловід Змії/Змія. Весна Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... А ми Йому Кінця не знайдем.','А в Кривого Танцю
Та не виведу Кінця
Треба Його та виводити
Кінець-Ладу ізнаходити','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236675'), datetime('now')),datetime('now'));
