INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236767','Бердо Бердо Бердовичко','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1944','1. Українські народні пісні з Лемківщини. Зібрав Орест Гижа. Заг.ред. С. Грици. Київ „Муз.Україна“ 1972. 403с.','Записана 1944 року від Гатали Олени (1909 р. н.) в селі Висова повіту Горлиці на Лемківщині. Діалектизми: бердовичка - Великодні гаївки; вшытки - всі; дуже - багато; медже - поміж; под - іди, ходи; розийдмеся - розійдімось. Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Вже Весна воскресла. Благослови Мати Весну закликати. Под же Дівча медже Нас. Як Нас дуже як величко.','Бердо, Бердо, Бердовичко,
Як Нас мало, невеличко,
Гей, гей, мало Нас,
Под же, Дівча, медже Нас!

Бердо, Бердо, Бердовичко,
Як Нас дуже, як величко,
Гей, гей, дуже Нас,
Розийдмеся вшытки враз!','[''pisni.org.ua'', ''cat:lemkivski'', ''cat:vesnyanky-hayivky'', ''Лемківські пісні'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236767'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_236767','Бердо Бердо Бердовичко','Бердо, Бердо, Бердовичко,
Як Нас мало, невеличко,
Гей, гей, мало Нас,
