INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_236828','Воротай-Воротайчику','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1978','1. Пісні з Поділля. - К.: Музична Україна, 1989. С. 18-19.','Записана 1978 року від Софії Іванівни Гащук (1928 р. н.) в с. Жабинці Чемеровецького району на Хмельниччині.','Воротай-Воротайчику,
Відтвори Воротонька,
Відтвори Воротонька,
Бо їде Сиротонька.

- Що ж то там за Пан їде,
Що ж то нам за Дар везе?
- Веземо тобі Дари,
Як всім Пчілонькам Яри.

- Ми Пчілок не беремо,
За Дари не приймемо.
- А що ж бо ви берете?
За Дари приймаєте?

- Золоте Ягняточко
За Крайнє Дівчаточко,
Золоте Ягняточко
За Крайнє Дівчаточко','[''pisni.org.ua'', ''cat:podilski'', ''cat:vesnyanky-hayivky'', ''Пісні з Поділля'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_236828'), datetime('now')),datetime('now'));
