INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2369522','Шкідлива звичка','Музика: Христина Соловій, Євген Соловій Слова: Христина Соловій. Виконує: Христина Соловій','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Не зупиняй назавжди час, в якому ми були,
Сумні на фото стали кораблі і літаки...
Дарма наздоганяти світ, їдемо в нікуди...
Просто тримай за руку і вези мене, вези...

Приспів:
Заховай хоча б кусочок           |
Нашого літа під сорочку...       |
Так буває - щось не вийшло,      |
А тобі личить шкідлива звичка... | (2)

І не шукай не наші в пам''яті спогади,
Як світлофори згасли за нами всі вони...
Де блисне день, а, де вже ніч падає в ноги,
І кораблі - у воду, і з неба літаки...

Приспів.

Я навчусь не відчувати роки,
Так боюсь залишитись напроти,
Доторкнутись і зруйнувати знаки твої,
Краще безглуздий сміх...

Приспів.','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2369522'), datetime('now')),datetime('now'));
