INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2368328','Виграва сопілонька','Музика: Микола Ведмедеря Слова: Катерина Перелісна','uk','ukraine_before_1917',NULL,NULL,'http://minus.lviv.ua/minus/artist/%D0%94%D0%B8%D1%82%D1%8F%D1%87% D0%B0/rec/35874/',NULL,'Виграва сопілонька у ліску,
Красується земленька у вінку.
Вітерець, пустуючи, шамотить,
Молодеє листячко мерехтить.

Приспів:
А у полі житечка - оксамит,
А над полем -сонечко і блакить,
І, мов легкі човники на морях,
Плинуть білі хмароньки в небесах...

І на річці хвилечка мов жива,
А у лісі сопілонька виграва,
Виграва сопілонька у ліску,
Красується земленька у вінку...

Приспів.','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2368328'), datetime('now')),datetime('now'));
