INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2369091','Вчителі','Музика: Назар Савко Слова: Назар Савко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Школа це кльово, дуже чудово!
Школа зустріне усіх гонорово!
Море цікавих предметів для нас,
Школа запрошує в кожен свій клас!
Тут фізкультура, там математика,
Фізика, хімія і інформатика.
Камінь науки гриземо щодня,
Хто нам дарує знання?

Приспів:
Вчителі, вчителі -   |
Наші другі батьки!   |
Ми до школи, до вас, |
Всі ідем залюбки!    | (2)

Школа це друзі, перше кохання,
Перші надії і сподівання,
Купа шпаргалок, брудні коліна,
В школі формуєшся ти, як людина!
Тут дискотеки і випускний,
Школа для нас то є скарб золотий!
Камінь науки гриземо щодня,
Хто нам дарує знання?

Приспів.

Руки догори! Руки догори! Школа!
Руки догори! Руки догори! Школа!
Руки догори! Руки догори! Школа!
Руки догори! Руки догори! Школа!
Руки догори! Руки догори!

Приспів.','[''pisni.org.ua'', ''cat:devoted'', ''cat:shkilni'', ''Пісні присвячені окремим особам'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2369091'), datetime('now')),datetime('now'));
